      PRmap = { 1.4638, 1.4598, 1.4565, 1.4543, 1.4521, 1.4408, 1.4204, 1.3955, 1.3609, 1.3137, 1.2594 }
   }
   NcMap = 0.800 {
      betaMap = { 0.00, 0.10, 0.20, 0.30, 0.40, 0.50, 0.60, 0.70, 0.80, 0.90, 1.00 }
      PRmap = { 1.6199, 1.6182, 1.6169, 1.6136, 1.6002, 1.5801, 1.5544, 1.5216, 1.4742, 1.4040, 1.2980 }
   }
   NcMap = 0.900 {
