      PRmap = { 1.8112, 1.8112, 1.8098, 1.8059, 1.7910, 1.7700, 1.7433, 1.7077, 1.6595, 1.5924, 1.5019 }
   }
   NcMap = 1.000 {
      betaMap = { 0.00, 0.10, 0.20, 0.30, 0.40, 0.50, 0.60, 0.70, 0.80, 0.90, 1.00 }
      PRmap = { 2.0265, 2.0178, 2.0046, 1.9880, 1.9684, 1.9401, 1.9137, 1.8812, 1.8244, 1.7171, 1.5549 }
   }
}

